function fetch1($pdo,$sql,$params=[]){$st=$pdo->prepare($sql);$st->execute($params);$r=$st->fetch(PDO::FETCH_ASSOC);return $r?:[];}
function scalar($pdo,$sql,$params=[]){$r=fetch1($pdo,$sql,$params);return array_values($r)[0]??0;}
if($_SERVER['REQUEST_METHOD']==='POST'){
