      else{$st=$pdo->prepare('INSERT INTO motocicletas (loja_id,modelo,marca,ano,placa,renavam,chassi,data_aquisicao,seguro,rastreador,status_operacional) VALUES (?,?,?,?,?,?,?,?,?,?,?)'); $st->execute([$_POST['loja_id'],$_POST['modelo'],$_POST['marca'],$_POST['ano'],$_POST['placa'],$_POST['renavam'],$_POST['chassi'],$_POST['data_aquisicao'],$_POST['seguro'],$_POST['rastreador'],$_POST['status_operacional']]);}
      $msg='Motocicleta salva com sucesso.';
    }
    if($acao==='contrato_salvar'){ exigir_perm('contratos','criar');
      $st=$pdo->prepare('INSERT INTO contratos (cliente_id,motocicleta_id,loja_id,data_inicio,valor_contratado,forma_cobranca,status,historico_alteracoes) VALUES (?,?,?,?,?,?,?,?)');
      $st->execute([$_POST['cliente_id'],$_POST['motocicleta_id'],$_POST['loja_id'],$_POST['data_inicio'],$_POST['valor_contratado'],$_POST['forma_cobranca'],$_POST['status'],'Contrato criado em '.date('d/m/Y H:i')]);
      $pdo->prepare('UPDATE motocicletas SET status_operacional="alugada" WHERE id=?')->execute([$_POST['motocicleta_id']]); $msg='Contrato criado.';
    }
    if($acao==='cobranca_salvar'){ exigir_perm('financeiro','criar');
      $contrato=fetch1($pdo,'SELECT * FROM contratos WHERE id=?',[$_POST['contrato_id']]);
      $st=$pdo->prepare('INSERT INTO cobrancas (contrato_id,cliente_id,loja_id,vencimento,valor_principal,valor_atualizado,status,pix_copia_cola,whatsapp_status) VALUES (?,?,?,?,?,?,?,?,?)');
      $pix='PIX-LOCX-'.date('YmdHis').'-'.rand(1000,9999);
      $st->execute([$contrato['id'],$contrato['cliente_id'],$contrato['loja_id'],$_POST['vencimento'],$_POST['valor_principal'],$_POST['valor_principal'],'aberta',$pix,'pendente']);
