    }
    if($acao==='pagamento_salvar'){ exigir_perm('financeiro','editar');
      $pdo->beginTransaction();
      $pdo->prepare('INSERT INTO pagamentos (cobranca_id,valor,forma,pago_em) VALUES (?,?,?,?)')->execute([$_POST['cobranca_id'],$_POST['valor'],$_POST['forma'],date('Y-m-d H:i:s')]);
      $c=fetch1($pdo,'SELECT * FROM cobrancas WHERE id=?',[$_POST['cobranca_id']]); $pago=(float)$c['valor_pago']+(float)$_POST['valor']; $atual=valor_atualizado($c['valor_principal'],$pago,$c['vencimento']); $status=$pago >= (float)$c['valor_principal'] ? 'paga' : 'parcial';
      $pdo->prepare('UPDATE cobrancas SET valor_pago=?,valor_atualizado=?,status=?,whatsapp_status=IF(?="paga","conciliado",whatsapp_status),atualizado_em=NOW() WHERE id=?')->execute([$pago,$atual,$status,$status,$_POST['cobranca_id']]);
      $pdo->commit(); $msg='Pagamento registrado.';
