    if($acao==='whatsapp_log'){ exigir_perm('cobrancas','editar');
      $pdo->prepare('INSERT INTO cobranca_logs (cobranca_id,tipo,mensagem) VALUES (?,?,?)')->execute([$_POST['cobranca_id'],$_POST['tipo'],$_POST['mensagem']]);
      $pdo->prepare('UPDATE cobrancas SET whatsapp_status="enviado" WHERE id=?')->execute([$_POST['cobranca_id']]); $msg='Histórico de cobrança registrado.';
    }
    if($acao==='whatsapp_config_salvar'){ exigir_perm('whatsapp','editar');
      $modo=$_POST['modo'] ?? 'demo';
      $ativo=(($_POST['ativo'] ?? '1')==='1')?1:0;
      $st=$pdo->prepare('INSERT INTO whatsapp_config (id,modo,phone_number_id,access_token,verify_token,template_cobranca,template_lembrete,template_bloqueio,ativo,atualizado_em) VALUES (1,?,?,?,?,?,?,?,?,NOW()) ON DUPLICATE KEY UPDATE modo=VALUES(modo),phone_number_id=VALUES(phone_number_id),access_token=VALUES(access_token),verify_token=VALUES(verify_token),template_cobranca=VALUES(template_cobranca),template_lembrete=VALUES(template_lembrete),template_bloqueio=VALUES(template_bloqueio),ativo=VALUES(ativo),atualizado_em=NOW()');
      $st->execute([$modo,$_POST['phone_number_id'],$_POST['access_token'],$_POST['verify_token'],$_POST['template_cobranca'],$_POST['template_lembrete'],$_POST['template_bloqueio'],$ativo]);
      $msg='Configurações do WhatsApp salvas.';
