    }
    if($acao==='whatsapp_enviar_cobranca'){ exigir_perm('inadimplencia','editar');
      $ret=whatsapp_enviar_cobranca($pdo,(int)$_POST['cobranca_id']);
      $msg=!empty($ret['ok']) ? 'Cobrança enviada pelo WhatsApp.' : 'Erro ao enviar WhatsApp: '.($ret['erro'] ?? 'falha desconhecida');
    }
    if($acao==='pagbank_salvar' || $acao==='pagbank_testar'){ exigir_perm('pagbank','editar');
      $modo = $_POST['modo'] ?? 'demo';
      // Normaliza valores antigos eventualmente salvos manualmente no banco.
      if(in_array($modo, ['api oficial','oficial','api_oficial'], true)) $modo = 'api';
      if(!in_array($modo, ['demo','api'], true)) $modo = 'demo';
      $ambiente = $_POST['ambiente'] ?? 'sandbox';
