      $ativo = (($_POST['ativo'] ?? '1') === '1') ? 1 : 0;
      $webhook = trim($_POST['webhook_url'] ?? '') ?: pagbank_webhook_padrao();
      $merchant = trim($_POST['merchant_reference'] ?? '') ?: 'LOCX';
      $st=$pdo->prepare('INSERT INTO pagbank_config (id,modo,ambiente,client_id,client_secret,access_token,webhook_url,merchant_reference,ativo,atualizado_em)
        VALUES (1,?,?,?,?,?,?,?,?,NOW())
        ON DUPLICATE KEY UPDATE modo=VALUES(modo),ambiente=VALUES(ambiente),client_id=VALUES(client_id),client_secret=VALUES(client_secret),access_token=VALUES(access_token),webhook_url=VALUES(webhook_url),merchant_reference=VALUES(merchant_reference),ativo=VALUES(ativo),atualizado_em=NOW()');
      $st->execute([$modo,$ambiente,trim($_POST['client_id'] ?? ''),trim($_POST['client_secret'] ?? ''),trim($_POST['access_token'] ?? ''),$webhook,$merchant,$ativo]);
      if($acao==='pagbank_testar'){
        $ret=pagbank_testar($pdo);
        if(!empty($ret['ok'])){
          $msg=$ret['mensagem'] ?? (!empty($ret['demo']) ? 'PagBank salvo. Modo demo ativo: nenhuma chamada externa foi feita.' : 'PagBank salvo. Conexão com a API PagBank realizada com sucesso.');
        }else{
          $msg='PagBank salvo, mas o teste falhou. HTTP '.($ret['http_code'] ?? 0).': '.($ret['erro'] ?? 'erro desconhecido');
        }
      }else{
        $msg='Configurações do PagBank salvas com sucesso.';
      }
    }
    if($acao==='pagbank_gerar_pix'){ exigir_perm('financeiro','editar');
      $ret=pagbank_criar_pix($pdo,(int)($_POST['cobranca_id'] ?? 0));
      $msg=!empty($ret['ok']) ? 'PIX PagBank gerado com sucesso para a cobrança.' : 'Erro ao gerar PIX PagBank: '.($ret['erro'] ?? 'falha desconhecida');
    }
    if($acao==='usuario_salvar'){ exigir_perm('usuarios','criar');
      $id=(int)($_POST['id'] ?? 0); $senha=$_POST['senha'] ?? ''; $lojas_sel=$_POST['lojas'] ?? []; $perms=$_POST['perms'] ?? [];
      if($id){ if($senha!==''){$st=$pdo->prepare('UPDATE usuarios SET nome=?,email=?,senha=?,perfil=?,loja_id=?,status=? WHERE id=?');$st->execute([$_POST['nome'],$_POST['email'],password_hash($senha,PASSWORD_DEFAULT),$_POST['perfil'],$_POST['loja_id']?:null,$_POST['status'],$id]);} else {$st=$pdo->prepare('UPDATE usuarios SET nome=?,email=?,perfil=?,loja_id=?,status=? WHERE id=?');$st->execute([$_POST['nome'],$_POST['email'],$_POST['perfil'],$_POST['loja_id']?:null,$_POST['status'],$id]);}}
      else{ if($senha==='') $senha='123456'; $st=$pdo->prepare('INSERT INTO usuarios (nome,email,senha,perfil,loja_id,status) VALUES (?,?,?,?,?,?)'); $st->execute([$_POST['nome'],$_POST['email'],password_hash($senha,PASSWORD_DEFAULT),$_POST['perfil'],$_POST['loja_id']?:null,$_POST['status']]); $id=$pdo->lastInsertId(); }
      $pdo->prepare('DELETE FROM usuario_lojas WHERE usuario_id=?')->execute([$id]); $ins=$pdo->prepare('INSERT INTO usuario_lojas (usuario_id,loja_id) VALUES (?,?)'); foreach($lojas_sel as $lid){$ins->execute([$id,$lid]);}
      $pdo->prepare('DELETE FROM usuario_permissoes WHERE usuario_id=?')->execute([$id]); $inp=$pdo->prepare('INSERT INTO usuario_permissoes (usuario_id,modulo,acao) VALUES (?,?,?)'); foreach($perms as $mod=>$acs){foreach($acs as $ac=>$v){$inp->execute([$id,$mod,$ac]);}}
      $msg='Usuário e permissionamentos salvos.';
    }
  }catch(Exception $e){ if($pdo->inTransaction())$pdo->rollBack(); $msg='Erro: '.$e->getMessage(); }
}
