function tabela_clientes($pdo){echo '<div class="table-wrap"><table><tr><th>Nome</th><th>CPF</th><th>WhatsApp</th><th>Status</th><th>Ações</th></tr>';foreach($pdo->query('SELECT * FROM clientes ORDER BY id DESC LIMIT 120') as $r){echo '<tr><td>'.e($r['nome']).'</td><td>'.e($r['cpf']).'</td><td>'.e($r['whatsapp']).'</td><td>'.tag_status($r['status']).'</td><td><a class="btn secondary" href="?page=clientes&edit='.$r['id'].'">Editar</a></td></tr>';}echo '</table></div>';}
function tabela_motos($pdo){$f=filtro_loja_sql('m');$st=$pdo->prepare('SELECT m.*,l.nome loja FROM motocicletas m JOIN lojas l ON l.id=m.loja_id WHERE 1=1'.$f['sql'].' ORDER BY m.id DESC LIMIT 150');$st->execute($f['params']);echo '<div class="table-wrap"><table><tr><th>Loja</th><th>Placa</th><th>Modelo</th><th>Ano</th><th>Status</th><th>Ações</th></tr>';foreach($st as $r){echo '<tr><td>'.e($r['loja']).'</td><td>'.e($r['placa']).'</td><td>'.e($r['modelo']).'</td><td>'.e($r['ano']).'</td><td>'.tag_status($r['status_operacional']).'</td><td><a class="btn secondary" href="?page=motos&edit='.$r['id'].'">Editar</a></td></tr>';}echo '</table></div>';}
function tabela_contratos($pdo){$f=filtro_loja_sql('c');$st=$pdo->prepare('SELECT c.*,cl.nome cliente,m.placa,l.nome loja FROM contratos c JOIN clientes cl ON cl.id=c.cliente_id JOIN motocicletas m ON m.id=c.motocicleta_id JOIN lojas l ON l.id=c.loja_id WHERE 1=1'.$f['sql'].' ORDER BY c.id DESC LIMIT 120');$st->execute($f['params']);echo '<div class="table-wrap"><table><tr><th>ID</th><th>Cliente</th><th>Moto</th><th>Loja</th><th>Valor</th><th>Status</th></tr>';foreach($st as $r){echo '<tr><td>#'.$r['id'].'</td><td>'.e($r['cliente']).'</td><td>'.e($r['placa']).'</td><td>'.e($r['loja']).'</td><td>'.moeda($r['valor_contratado']).'</td><td>'.tag_status($r['status']).'</td></tr>';}echo '</table></div>';}
function tabela_cobrancas($pdo){
  $f=filtro_loja_sql('cb');
  $st=$pdo->prepare('SELECT cb.*,cl.nome cliente FROM cobrancas cb JOIN clientes cl ON cl.id=cb.cliente_id WHERE 1=1'.$f['sql'].' ORDER BY cb.id DESC LIMIT 160');
  $st->execute($f['params']);
  echo '<div class="table-wrap"><table><tr><th>ID</th><th>Cliente</th><th>Vencimento</th><th>Principal</th><th>Pago</th><th>Atualizado</th><th>PIX/WhatsApp</th><th>PagBank</th><th>Status</th></tr>';
  foreach($st as $r){
    $atual=valor_atualizado($r['valor_principal'],$r['valor_pago'],$r['vencimento']);
    if($r['status']!=='paga' && abs($atual-$r['valor_atualizado'])>0.01){
      $pdo->prepare('UPDATE cobrancas SET valor_atualizado=?, status=IF(vencimento<CURDATE(),"atrasada",status) WHERE id=?')->execute([$atual,$r['id']]);
      $r['valor_atualizado']=$atual;
      if(strtotime($r['vencimento'])<strtotime(date('Y-m-d'))) $r['status']='atrasada';
    }
    $pixInfo = !empty($r['pix_copia_cola']) ? 'PIX gerado' : 'Sem PIX';
    $pagStatus = !empty($r['pagbank_status']) ? tag_status($r['pagbank_status']) : '<span class="tag muted">não gerado</span>';
    echo '<tr><td>#'.$r['id'].'</td><td>'.e($r['cliente']).'</td><td>'.date('d/m/Y',strtotime($r['vencimento'])).'</td><td>'.moeda($r['valor_principal']).'</td><td>'.moeda($r['valor_pago']).'</td><td>'.moeda($r['valor_atualizado']).'</td><td>'.e($pixInfo).' / '.tag_status($r['whatsapp_status']??'pendente').'</td><td><div class="actions"><form method="post" style="display:inline"><input type="hidden" name="acao" value="pagbank_gerar_pix"><input type="hidden" name="cobranca_id" value="'.(int)$r['id'].'"><button class="btn secondary" type="submit">Gerar PIX</button></form></div><br>'.$pagStatus.'</td><td>'.tag_status($r['status']).'</td></tr>';
  }
  echo '</table></div>';
}
function tabela_inadimplencia($pdo){$st=$pdo->query('SELECT cb.*,cl.nome,cl.whatsapp,m.placa FROM cobrancas cb JOIN clientes cl ON cl.id=cb.cliente_id LEFT JOIN contratos ct ON ct.id=cb.contrato_id LEFT JOIN motocicletas m ON m.id=ct.motocicleta_id WHERE cb.vencimento<CURDATE() AND cb.status<>"paga" ORDER BY cb.vencimento ASC');echo '<div class="table-wrap"><table><tr><th>Cliente</th><th>Moto</th><th>Dias</th><th>Saldo Original</th><th>Pago</th><th>Atualizado</th><th>WhatsApp</th></tr>';foreach($st as $r){$dias=dias_atraso_ate_domingo($r['vencimento']);$atual=valor_atualizado($r['valor_principal'],$r['valor_pago'],$r['vencimento']);$wa='https://wa.me/55'.preg_replace('/\D/','',$r['whatsapp']);echo '<tr><td>'.e($r['nome']).'</td><td>'.e($r['placa']).'</td><td>'.$dias.'</td><td>'.moeda($r['valor_principal']).'</td><td>'.moeda($r['valor_pago']).'</td><td>'.moeda($atual).'</td><td><div class="actions"><a class="btn secondary" target="_blank" href="'.$wa.'">Abrir</a><form method="post" style="display:inline"><input type="hidden" name="acao" value="whatsapp_enviar_cobranca"><input type="hidden" name="cobranca_id" value="'.(int)$r['id'].'"><button class="btn success" type="submit">Enviar API</button></form></div></td></tr>';}echo '</table></div>';}
function tabela_whatsapp_logs($pdo){try{$st=$pdo->query('SELECT wl.*,cl.nome cliente FROM whatsapp_logs wl LEFT JOIN clientes cl ON cl.id=wl.cliente_id ORDER BY wl.id DESC LIMIT 80');echo '<div class="table-wrap"><table><tr><th>Data</th><th>Cliente</th><th>Telefone</th><th>Tipo</th><th>Status</th><th>HTTP</th></tr>';foreach($st as $r){echo '<tr><td>'.date('d/m/Y H:i',strtotime($r['criado_em'])).'</td><td>'.e($r['cliente']??'-').'</td><td>'.e($r['telefone']).'</td><td>'.e($r['tipo']).'</td><td>'.tag_status($r['status']).'</td><td>'.e($r['http_code']??'-').'</td></tr>';}echo '</table></div>';}catch(Throwable $e){echo '<div class="empty">Execute atualizar_banco.php para criar as tabelas do WhatsApp.</div>';}}

function tabela_usuarios($pdo){echo '<div class="table-wrap"><table><tr><th>Nome</th><th>E-mail</th><th>Perfil</th><th>Loja principal</th><th>Status</th><th>Ações</th></tr>';foreach($pdo->query('SELECT u.*,l.nome loja FROM usuarios u LEFT JOIN lojas l ON l.id=u.loja_id ORDER BY u.id DESC') as $r){echo '<tr><td>'.e($r['nome']).'</td><td>'.e($r['email']).'</td><td>'.e(perfil_nome($r['perfil'])).'</td><td>'.e($r['loja'] ?: 'Todas / Central').'</td><td>'.tag_status($r['status']).'</td><td><a class="btn secondary" href="?page=usuarios&edit='.$r['id'].'">Editar</a></td></tr>';}echo '</table></div>';}
function tabela_lojas_resumo($pdo){echo '<div class="table-wrap"><table><tr><th>Loja</th><th>Motos</th><th>Alugadas</th><th>Disponíveis</th><th>Recebido</th><th>Em atraso</th></tr>';foreach($pdo->query('SELECT * FROM lojas ORDER BY nome') as $l){$m=scalar($pdo,'SELECT COUNT(*) FROM motocicletas WHERE loja_id=?',[$l['id']]);$a=scalar($pdo,'SELECT COUNT(*) FROM motocicletas WHERE loja_id=? AND status_operacional="alugada"',[$l['id']]);$d=scalar($pdo,'SELECT COUNT(*) FROM motocicletas WHERE loja_id=? AND status_operacional="disponivel"',[$l['id']]);$rec=scalar($pdo,'SELECT COALESCE(SUM(p.valor),0) FROM pagamentos p JOIN cobrancas c ON c.id=p.cobranca_id WHERE c.loja_id=?',[$l['id']]);$at=scalar($pdo,'SELECT COALESCE(SUM(valor_atualizado-valor_pago),0) FROM cobrancas WHERE loja_id=? AND vencimento<CURDATE() AND status<>"paga"',[$l['id']]);echo '<tr><td>'.e($l['nome']).'</td><td>'.$m.'</td><td>'.$a.'</td><td>'.$d.'</td><td>'.moeda($rec).'</td><td>'.moeda($at).'</td></tr>';}echo '</table></div>';}
?>
